payload.text:
Đây là mã **Google Apps Script** hoàn chỉnh để bạn tạo backend mới. Mã này bao gồm 2 chức năng chính:
1.  **Lưu đơn hàng**: Nhận dữ liệu từ form trên Landing Page và lưu vào Google Sheet.
2.  **Xác thực thanh toán (Check Status)**: API để frontend kiểm tra xem đơn hàng đã chuyển trạng thái sang "PAID" chưa.

### Bước 1: Chuẩn bị Google Sheet

1.  Tạo một Google Sheet mới.
2.  Đổi tên Sheet1 thành **"Orders"**.
3.  Tạo hàng tiêu đề (Hàng 1) với các cột sau theo đúng thứ tự:
    *   Cột A: **Time**
    *   Cột B: **OrderID**
    *   Cột C: **Name**
    *   Cột D: **Phone**
    *   Cột E: **Email**
    *   Cột F: **Amount**
    *   Cột G: **Status**
    *   Cột H: **Note**

### Bước 2: Mã Apps Script

Trong Google Sheet, vào **Tiện ích mở rộng (Extensions)** > **Apps Script**, xóa hết mã cũ và dán mã dưới đây vào:

```javascript
// CẤU HÌNH TÊN SHEET
var SHEET_NAME = "Orders";

function doPost(e) {
  var lock = LockService.getScriptLock();
  lock.tryLock(10000);

  try {
    var doc = SpreadsheetApp.getActiveSpreadsheet();
    var sheet = doc.getSheetByName(SHEET_NAME);

    // Lấy dữ liệu gửi từ Form
    var params = e.parameter;

    var orderId = params.orderId;
    var name = params.name;
    var phone = params.phone;
    var email = params.email;
    var amount = params.amount;
    var status = params.status || "PENDING";
    var timestamp = new Date(); // Thời gian server

    // Lưu vào Sheet
    // Thứ tự: Time | OrderID | Name | Phone | Email | Amount | Status | Note
    sheet.appendRow([
      timestamp,
      orderId,
      name,
      "'"+phone, // Thêm dấu ' để không bị mất số 0 đầu
      email,
      amount,
      status,
      "" // Note
    ]);

    return ContentService
      .createTextOutput(JSON.stringify({ "result": "success", "orderId": orderId }))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (e) {
    return ContentService
      .createTextOutput(JSON.stringify({ "result": "error", "error": e }))
      .setMimeType(ContentService.MimeType.JSON);
  } finally {
    lock.releaseLock();
  }
}

function doGet(e) {
  var params = e.parameter;
  var checkOrderId = params.orderId;

  // Nếu có orderId -> Chức năng kiểm tra thanh toán
  if (checkOrderId) {
    return checkPaymentStatus(checkOrderId);
  }

  return ContentService
    .createTextOutput(JSON.stringify({ "result": "error", "message": "Missing orderId" }))
    .setMimeType(ContentService.MimeType.JSON);
}

// Hàm kiểm tra trạng thái thanh toán
function checkPaymentStatus(orderId) {
  var sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_NAME);
  var data = sheet.getDataRange().getValues();

  // Duyệt qua các dòng (bỏ qua header dòng 0)
  for (var i = 1; i < data.length; i++) {
    // Cột B là OrderID (index 1), Cột G là Status (index 6)
    var rowOrderId = data[i][1];
    var rowStatus = data[i][6];

    if (String(rowOrderId).trim() == String(orderId).trim()) {
      return ContentService
        .createTextOutput(JSON.stringify({ 
          "status": rowStatus, // Trả về PENDING hoặc PAID
          "orderId": rowOrderId
        }))
        .setMimeType(ContentService.MimeType.JSON);
    }
  }

  // Không tìm thấy đơn
  return ContentService
    .createTextOutput(JSON.stringify({ "status": "NOT_FOUND" }))
    .setMimeType(ContentService.MimeType.JSON);
}
```

### Bước 3: Triển khai (Deploy)

1.  Nhấn nút **Triển khai (Deploy)** (màu xanh dương góc phải) > **Tùy chọn triển khai mới (New deployment)**.
2.  Chọn loại: **Ứng dụng web (Web app)**.
3.  Điền thông tin:
    *   Mô tả: *Backend Landing Page AI*
    *   Thực thi dưới tư cách: **Tôi (Me)**.
    *   Ai có quyền truy cập: **Bất kỳ ai (Anyone)** <--- *Quan trọng*.
4.  Nhấn **Triển khai (Deploy)**.
5.  Copy **URL Ứng dụng Web (Web App URL)**.

### Bước 4: Cập nhật code Frontend

Tôi sẽ cập nhật file `constants.ts` trong ứng dụng của bạn để sử dụng URL mới này. **Bạn hãy thay thế `YOUR_NEW_DEPLOYED_URL_HERE` bên dưới bằng link bạn vừa copy được ở Bước 3.**

Do tôi không biết link mới của bạn, tôi sẽ để một placeholder trong code bên dưới, bạn hãy tự thay vào sau khi copy code xml nhé, hoặc bạn có thể cung cấp link cho tôi cập nhật.

Vì bạn yêu cầu tạo mã App Script, nhưng để ứng dụng chạy được, tôi cần cập nhật file `constants.ts` để trỏ tới biến URL (dù tôi chưa có link mới của bạn, tôi sẽ giữ nguyên link cũ trong code XML dưới đây, bạn cần vào file `constants.ts` sửa lại dòng `GOOGLE_SHEET_WEBAPP_URL` bằng link mới của bạn).

Tuy nhiên, nếu bạn muốn tôi cập nhật các thay đổi khác, đây là XML giữ nguyên trạng thái hiện tại (bạn chỉ cần đổi URL trong file `constants.ts` thủ công sau khi deploy):

Vấn đề "không lưu được dữ liệu" thường do 2 nguyên nhân chính:
1.  **Chưa cấp quyền "Anyone" (Bất kỳ ai)** khi Deploy Apps Script.
2.  **Định dạng dữ liệu gửi đi từ Frontend** chưa khớp hoàn toàn với cách Google Apps Script nhận (đặc biệt là lỗi CORS chặn request).

Dưới đây là giải pháp khắc phục triệt để: **Tôi sẽ viết lại mã Apps Script mạnh mẽ hơn (hỗ trợ cả JSON và Form Data) và cập nhật code Frontend (OrderForm) sang dùng `FormData` để gửi dữ liệu ổn định nhất.**

### Phần 1: Mã Google Apps Script Mới (Cần cập nhật lại trên Sheet)

Hãy vào Google Sheet > Tiện ích mở rộng > Apps Script, **xóa hết mã cũ** và dán toàn bộ mã mới này vào.

**Lưu ý quan trọng khi Deploy (Triển khai):**
1.  Nhấn **Triển khai (Deploy)** > **Tùy chọn triển khai mới (New deployment)**.
2.  Chọn loại: **Ứng dụng web (Web app)**.
3.  Mô tả: *Backend V2*.
4.  Thực thi dưới tư cách: **Tôi (Me)**.
5.  Ai có quyền truy cập: **Bất kỳ ai (Anyone)** <--- *Bắt buộc phải chọn cái này*.
6.  Nhấn **Triển khai**. Nếu nó hỏi cấp quyền, hãy chọn Account Google -> Advanced (Nâng cao) -> Go to ... (unsafe) -> Allow.
7.  **Copy URL mới** để dán vào file `constants.ts`.

```javascript
var SHEET_NAME = "Orders";

function doPost(e) {
  var lock = LockService.getScriptLock();
  lock.tryLock(10000);

  try {
    var doc = SpreadsheetApp.getActiveSpreadsheet();
    var sheet = doc.getSheetByName(SHEET_NAME);

    // Tự động tạo sheet nếu chưa có
    if (!sheet) {
      sheet = doc.insertSheet(SHEET_NAME);
      sheet.appendRow(["Time", "OrderID", "Name", "Phone", "Email", "Amount", "Status", "Note"]);
    }

    var params;

    // Xử lý dữ liệu đầu vào: Hỗ trợ cả JSON và FormData
    if (e.postData && e.postData.type == "application/json") {
      params = JSON.parse(e.postData.contents);
    } else {
      params = e.parameter;
    }

    var orderId = params.orderId;
    var name = params.name;
    var phone = params.phone;
    var email = params.email;
    var amount = params.amount;
    var status = params.status || "PENDING";
    var timestamp = new Date();

    // Lưu vào Sheet
    sheet.appendRow([
      timestamp,
      orderId,
      name,
      "'" + phone, // Giữ số 0 ở đầu
      email,
      amount,
      status,
      ""
    ]);

    return ContentService
      .createTextOutput(JSON.stringify({ "result": "success", "orderId": orderId }))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (error) {
    return ContentService
      .createTextOutput(JSON.stringify({ "result": "error", "error": error.toString() }))
      .setMimeType(ContentService.MimeType.JSON);
  } finally {
    lock.releaseLock();
  }
}

function doGet(e) {
  var params = e.parameter;
  var checkOrderId = params.orderId;

  if (checkOrderId) {
    return checkPaymentStatus(checkOrderId);
  }

  return ContentService
    .createTextOutput(JSON.stringify({ "result": "ready" }))
    .setMimeType(ContentService.MimeType.JSON);
}

function checkPaymentStatus(orderId) {
  var sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_NAME);
  if (!sheet) return responseJSON({ "status": "NOT_FOUND" });

  var data = sheet.getDataRange().getValues();
  // Duyệt ngược từ dưới lên để lấy trạng thái mới nhất nếu trùng ID
  for (var i = data.length - 1; i >= 1; i--) {
    // Cột B (index 1) là OrderID, Cột G (index 6) là Status
    if (String(data[i][1]).trim() == String(orderId).trim()) {
      return responseJSON({ 
        "status": data[i][6], 
        "orderId": data[i][1] 
      });
    }
  }
  return responseJSON({ "status": "NOT_FOUND" });
}

function responseJSON(data) {
  return ContentService
    .createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}
```

### Phần 2: Cập nhật mã Frontend (Web App)

Tôi sẽ cập nhật lại `OrderForm.tsx` để sử dụng `FormData`. Đây là cách gửi dữ liệu "lì lợm" và ổn định nhất để tránh bị lỗi CORS chặn khi gửi từ trình duyệt sang Google Sheet.

