        {/* Sale Badge & Text */}
        <div className="flex items-center justify-center gap-2 w-full sm:w-auto">
          <div className="flex items-center gap-2">
            <span className="bg-rose-600 text-white text-[10px] md:text-xs font-black px-2 py-0.5 rounded shadow-sm uppercase tracking-tighter whitespace-nowrap flex items-center gap-1 animate-pulse">
